INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-8b44517b-moex-00447', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '勞動基準法中處以有期徒刑、拘役或科或併科罰金，乃是勞動刑罰的形式之一，下列何項非屬勞動刑罰 處分之行為？', '["拒絕或阻撓勞工檢查員依法執行職務", "童工於午後八時至翌晨六時之時間內工作", "介入他人之勞動契約，抽取不法利益", "強制勞工從事勞動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00448', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依勞動基準法之規定，下列有關退休金之敘述，何者正確？', '["按其工作年資，每滿一年給與一個基數。但超過十五年之工作年資，每滿一年給與二個基數，最高總 數以四十五個基數為限", "退休金基數之標準，係指核准退休時一個月實質工資", "勞工請領退休金之權利，自退休之次月起，因二年間不行使而消滅", "雇主應依勞工每月薪資總額百分之二至百分之十五範圍內，按月提撥勞工退休準備金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00449', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '勞動基準法中規定雇主應備置勞工名卡，且保管至勞工離職後五年。請問該法列舉之勞工名卡應載事項 中，不包括下列何項？', '["婚姻", "本籍", "獎懲", "性別"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00450', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '曾以行政命令執行之「調動勞工工作五原則」，現已載入勞動基準法中，其規定不包括下列那項？', '["考量勞工及其家庭之生活利益", "調動後工作為勞工知能及專業可勝任", "調動工作地點過遠，雇主應予以必要之協助", "對勞工之工資及其他勞動條件，未作不利之變更"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00451', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '勞動基準法中有關派遣勞動的規定，下列敘述何者正確？', '["要派單位得於派遣事業單位與派遣勞工簽訂勞動契約前，先面試該派遣勞工", "要派單位應自派遣勞工意思表示到達之日起十日內，與其協商訂定勞動契約。逾期未協商或協商不成 立者，視為不成立勞動契約", "要派單位使用派遣勞工發生職業災害時，要派單位應與派遣事業單位連帶負雇主應負職業災害補償之 責任", "派遣事業單位積欠派遣勞工工資，派遣勞工得依法請求要派單位給付。要派單位應自派遣勞工請求之 日起六十日內給付之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00452', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依據勞工退休金條例之規定，勞工於請領退休金前死亡，法定請領退休金遺屬之第一順位為何？', '["配偶", "子女", "配偶及子女", "父母、配偶及子女"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00453', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '有關促進性別平等措施之描述，下列何者錯誤？', '["產檢假七日", "妊娠未滿二個月流產者，應使其停止工作，給予產假五日", "家庭照顧假，全年以七日為限", "家庭照顧假併入病假計算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00454', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '性別工作平等法中處理申訴案件之期程規定，下列何者正確？', '["地方主管機關應於接獲申訴後十日內展開調查", "中央主管機關應於收受申訴案件，十日內移送地方主管機關", "對於地方主管機關所為之處分有異議時，得於三十日內向中央主管機關性別工作平等會申請審議", "對於地方主管機關所為之處分有異議時，得逕行提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00455', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '有關職業安全衛生法中之安全衛生措施規定，下列敘述何者錯誤？', '["使用危害性之化學品數量達中央主管機關規定量以上之工作場所，應制定年度風險評估報告，報主管 機關備查", "雇主對於經中央主管機關指定之作業場所，應訂定作業環境監測計畫", "雇主對於具有危害性之化學品，應予揭示安全資料表", "從事石油裂解之石化工業之工作場所，事業單位應製作製程安全評估報告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00456', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '雇主得僱用未滿十八歲者從事下列那項工作？', '["處理爆炸性、易燃性等物質之工作", "高樓板模灌漿工作", "已熔礦物或礦渣之處理", "起重機之運轉工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "13c76683e26f", "answer_pdf_sha1": "1aafe3df6497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
